const MEASUREMENT_TYPES = ['temperature', 'humidity', 'pressure', 'voltage', 'light'];
const segments = msg.topic.split('/');

// Must be exactly 6 segments: iot/{site}/{gateway_id}/{location}/{device_id}/{measurement}
if (segments.length !== 6 || segments[0] !== 'iot') {
    // Route to output 2 so the drop is visible in the debug sidebar
    return [null, { payload: 'Dropped — bad topic structure: ' + msg.topic }];
}

const [, site, gateway_id, location, device_id, measurement] = segments;

// Silently drop lifecycle topics (status, events, commands)
if (!MEASUREMENT_TYPES.includes(measurement)) {
    return;
}

const payload = msg.payload;

if (typeof payload.value !== 'number') {
    node.error('Missing or non-numeric value in payload on topic ' + msg.topic, msg);
    return;
}

if (!payload.timestamp) {
    node.error('Missing timestamp in payload on topic ' + msg.topic, msg);
    return;
}

const ts = new Date(payload.timestamp);
if (isNaN(ts.getTime())) {
    node.error('Invalid timestamp "' + payload.timestamp + '" on topic ' + msg.topic, msg);
    return;
}

msg.parsed = {
    site: site,
    gateway_id: gateway_id,
    location: location,
    device_id: device_id,
    measurement: measurement,
    value: payload.value,
    unit: payload.unit || '',
    timestamp: ts
};

return [msg, null];

const { site, gateway_id, location, device_id, measurement, value, unit, timestamp } = msg.parsed;

msg.payload = [{
    measurement: 'sensor_reading',
    tags: {
        site: site,
        gateway_id: gateway_id,
        location: location,
        device_id: device_id,
        measurement_type: measurement,
        unit: unit
    },
    fields: {
        value: value
    },
    timestamp: timestamp
}];

return msg;

// ── recipient ── set your address here ──────────────────────────
const RECIPIENT = 'YOUR_EMAIL@gmail.com';
// ─────────────────────────────────────────────────────────────────

const rows = msg.payload || [];
const now = new Date().toLocaleString('fi-FI', { timeZone: 'Europe/Helsinki' });

// Group rows by device_id
const byDevice = {};
for (const r of rows) {
    const dev = r.device_id || 'unknown';
    if (!byDevice[dev]) byDevice[dev] = [];
    byDevice[dev].push(r);
}

let html = `<h2 style="font-family:sans-serif">IoT Sensor Report</h2>`;
html += `<p style="font-family:sans-serif;color:#555">Generated: ${now}</p>`;

if (rows.length === 0) {
    html += '<p style="font-family:sans-serif;color:#c00"><strong>No data received in the last 12 hours.</strong></p>';
} else {
    for (const [device, readings] of Object.entries(byDevice)) {
        html += `<h3 style="font-family:sans-serif">${device}</h3>`;
        html += '<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-family:sans-serif;font-size:14px">';
        html += '<tr style="background:#f0f0f0"><th>Measurement</th><th>Value</th><th>Unit</th><th>Time (EET)</th></tr>';
        for (const r of readings) {
            const t = r._time ? new Date(r._time).toLocaleString('fi-FI', { timeZone: 'Europe/Helsinki' }) : '—';
            const val = typeof r._value === 'number' ? r._value.toFixed(2) : (r._value || '—');
            html += `<tr><td>${r.measurement_type || '—'}</td><td>${val}</td><td>${r.unit || '—'}</td><td>${t}</td></tr>`;
        }
        html += '</table><br>';
    }
}

msg.to = RECIPIENT;
msg.topic = 'IoT Sensor Report — ' + now;
msg.payload = html;
return msg;

// ── recipient ── set your address here ──────────────────────────
const RECIPIENT = 'YOUR_EMAIL@gmail.com';
// 4-hour cooldown between repeated alerts
const ALERT_COOLDOWN_HOURS = 4;
// ─────────────────────────────────────────────────────────────────

const rows = msg.payload || [];
const total = rows.reduce((s, r) => s + (r._value || 0), 0);

if (total > 0) {
    // Data is flowing — clear alert state so next outage fires fresh
    flow.set('alertSent', false);
    return null;
}

// No data in last 1 hour — check cooldown
const lastSent = flow.get('lastAlertSent') || 0;
const hoursSince = (Date.now() - lastSent) / 3600000;

if (hoursSince < ALERT_COOLDOWN_HOURS) {
    return null;  // suppress: already alerted recently
}

flow.set('lastAlertSent', Date.now());
flow.set('alertSent', true);

const sinceWhen = new Date(Date.now() - 3600000).toLocaleString('fi-FI', { timeZone: 'Europe/Helsinki' });
msg.to = RECIPIENT;
msg.topic = '⚠️ IoT Alert — No sensor data for 1+ hour';
msg.payload = `No sensor measurements have been received since ${sinceWhen} (EET).\n\nPlease check the gateway and sensor node.`;
return msg;
